body.content:
MainScheduler.ensureExecutingOnScheduler()

        if self._running {
            return
        }

        self._running = true
        repeat {
            guard let next = self.findNext() else {
                break
            }

            if self._converter.compareVirtualTime(next.time, self.clock).greaterThan {
                self._clock = next.time
            }

            next.invoke()
            self._schedulerQueue.remove(next)
        } while self._running

        self._running = false
